class ETGRegistrationTypeCache
{
    private static Map regTypeMap = new Map(Types::Int64, Types::String);

}

Method.Source:
public static void setOldValue(RefRecId recId, str oldValue)
{
    regTypeMap.insert(recId, oldValue);
}

public static str getOldValue(RefRecId recId)
{
    return regTypeMap.exists(recId) ? regTypeMap.lookup(recId) : "";
}

public static void clear(RefRecId recId)
{
    regTypeMap.remove(recId);
}
